export type StartVotingParams = {
  userId: string;
  durationSeconds?: number;
  latitude: number;
  longitude: number;
};

/** Resolves options via Google Places (backend) using location, then starts voting. */
export async function startTimer(
  roomCode: string,
  params: StartVotingParams
): Promise<void> {
  const { userId, durationSeconds = 60, latitude, longitude } = params;
  return tryApi(
    () =>
      fetchApi(`/api/rooms/${roomCode}/start`, {
        method: "POST",
        body: JSON.stringify({
          userId,
          durationSeconds,
          latitude,
          longitude,
        }),
      }),
    async () => {
      const { mockStartTimer } = await import("./mock");
      return mockStartTimer(roomCode, durationSeconds, latitude, longitude);
    }
  );
}

export async function restartRoom(roomCode: string, userId: string): Promise<Room> {
  return tryApi(
    () =>
      fetchApi<Room>(`/api/rooms/${roomCode}/restart`, {
        method: "POST",
        body: JSON.stringify({ userId }),
      }),
    async () => {
      const { mockRestartRoom } = await import("./mock");
      return mockRestartRoom(roomCode);
    }
  );
}

export async function getRoom(roomCode: string): Promise<Room> {
  return tryApi(
    () => fetchApi<Room>(`/api/rooms/${roomCode}`),
    async () => {
      const { mockGetRoom } = await import("./mock");
      const room = mockGetRoom(roomCode);
      if (!room) throw new Error("Room not found");
      return room;
    }
  );
}

export { API_BASE };
