"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { createRoom } from "@/lib/api";

export default function CreateRoomPage() {
  const router = useRouter();
  const [name, setName] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim()) return;
    setLoading(true);
    setError("");
    try {
      const { room, user } = await createRoom(name.trim());
      localStorage.setItem("userId", user.id);
      localStorage.setItem("userName", user.name);
      router.push(`/room/${room.code}`);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to create room");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex min-h-screen flex-col items-center justify-center bg-[#f8fafc] p-6">
      <Link
        href="/"
        className="absolute left-4 top-4 text-[#6d28d9] font-semibold hover:underline"
      >
        ← Back
      </Link>
      <main className="w-full max-w-md">
        <h2 className="mb-8 text-center text-2xl font-bold text-[#1e1b4b]">
          Create a Room
        </h2>
        <form
          onSubmit={handleSubmit}
          className="rounded-3xl border-4 border-[#6d28d9] bg-white p-8 shadow-xl"
        >
          <label htmlFor="name" className="mb-2 block font-semibold text-[#475569]">
            Your name
          </label>
          <input
            id="name"
            type="text"
            value={name}
            onChange={(e) => setName(e.target.value)}
            placeholder="Host"
            required
            maxLength={32}
            className="mb-6 w-full rounded-xl border-2 border-[#e2e8f0] px-4 py-3 text-lg focus:border-[#6d28d9] focus:outline-none"
          />
          {error && (
            <p className="mb-4 text-sm text-[#dc2626]">{error}</p>
          )}
          <button
            type="submit"
            disabled={loading}
            className="w-full rounded-xl bg-[#6d28d9] py-4 text-lg font-bold text-white transition hover:bg-[#5b21b6] disabled:opacity-50"
          >
            {loading ? "Creating..." : "Create Room"}
          </button>
        </form>
      </main>
    </div>
  );
}
